#nullable enable // autogenerated

using System;
using MVZ2.Vanilla.Detections;
using MVZ2Logic.Level;
using PVZEngine.Collisions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Detections
{
    public class LawnDetector : Detector
    {
        public LawnDetector()
        {
        }
        protected override Bounds GetDetectionBounds(Entity self)
        {
            var minX = 0;
            var maxX = LevelPositions.LEVEL_WIDTH;
            var minZ = 0;
            var maxZ = LevelPositions.LAWN_HEIGHT;
            var sizeY = 800;
            var center = self.GetCenter();
            center.x = (minX + maxX) * 0.5f;
            center.y = sizeY * 0.5f;
            center.z = (minZ + maxZ) * 0.5f;
            return new Bounds(center, new Vector3(maxX - minX, sizeY, maxZ - minZ));
        }
        protected override bool ValidateCollider(DetectionParams param, IEntityCollider collider)
        {
            if (colliderFilter != null && !colliderFilter(param, collider))
                return false;
            return base.ValidateCollider(param, collider);
        }
        public Func<DetectionParams, IEntityCollider, bool>? colliderFilter;
    }
}
